import React from 'react';
import { Link } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import '../styles/Footer.css';

const Footer = () => {
    const { t } = useTranslation();

    return (
        <footer className="footer bg-gray-900 dark:bg-gray-950 transition-colors duration-300">
            <div className="footer-wave">
                <svg viewBox="0 0 1200 120" preserveAspectRatio="none" className="text-gray-800 dark:text-gray-900 transition-colors duration-300">
                    <path d="M321.39,56.44c58-10.79,114.16-30.13,172-41.86,82.39-16.72,168.19-17.73,250.45-.39C823.78,31,906.67,72,985.66,92.83c70.05,18.48,146.53,26.09,214.34,3V0H0V27.35A600.21,600.21,0,0,0,321.39,56.44Z" fill="currentColor"></path>
                </svg>
            </div>

            <div className="footer-content">
                <div className="container">
                    {/* Main Footer Content */}
                    <div className="footer-main">
                        <div className="footer-section footer-about">
                            <div className="footer-logo">
                                <h3 className="text-white dark:text-gray-100 transition-colors duration-300">FIA Portal</h3>
                                <span className="logo-tagline text-blue-400 dark:text-blue-300 transition-colors duration-300">{t('footer.tagline')}</span>
                            </div>
                            <p className="footer-description text-gray-300 dark:text-gray-400 transition-colors duration-300">
                                {t('footer.description')}
                            </p>
                            <div className="footer-social">
                                <a href="https://facebook.com" target="_blank" rel="noopener noreferrer" 
                                   className="social-link bg-blue-600 hover:bg-blue-700 dark:bg-blue-500 dark:hover:bg-blue-600 text-white transition-all duration-300">
                                    <i className="fab fa-facebook-f"></i>
                                </a>
                                <a href="https://twitter.com" target="_blank" rel="noopener noreferrer"
                                   className="social-link bg-sky-500 hover:bg-sky-600 dark:bg-sky-400 dark:hover:bg-sky-500 text-white transition-all duration-300">
                                    <i className="fab fa-twitter"></i>
                                </a>
                                <a href="https://instagram.com" target="_blank" rel="noopener noreferrer"
                                   className="social-link bg-pink-500 hover:bg-pink-600 dark:bg-pink-400 dark:hover:bg-pink-500 text-white transition-all duration-300">
                                    <i className="fab fa-instagram"></i>
                                </a>
                                <a href="https://linkedin.com" target="_blank" rel="noopener noreferrer"
                                   className="social-link bg-blue-700 hover:bg-blue-800 dark:bg-blue-600 dark:hover:bg-blue-700 text-white transition-all duration-300">
                                    <i className="fab fa-linkedin-in"></i>
                                </a>
                                <a href="https://youtube.com" target="_blank" rel="noopener noreferrer"
                                   className="social-link bg-red-600 hover:bg-red-700 dark:bg-red-500 dark:hover:bg-red-600 text-white transition-all duration-300">
                                    <i className="fab fa-youtube"></i>
                                </a>
                            </div>
                        </div>

                        <div className="footer-section">
                            <h4 className="footer-title text-white dark:text-gray-100 transition-colors duration-300">{t('footer.quickLinks.title')}</h4>
                            <ul className="footer-links">
                                <li><Link to="/" className="text-gray-300 dark:text-gray-400 hover:text-blue-400 dark:hover:text-blue-300 transition-colors duration-300">{t('footer.quickLinks.home')}</Link></li>
                                <li><Link to="/about" className="text-gray-300 dark:text-gray-400 hover:text-blue-400 dark:hover:text-blue-300 transition-colors duration-300">{t('footer.quickLinks.about')}</Link></li>
                                <li><Link to="/courses" className="text-gray-300 dark:text-gray-400 hover:text-blue-400 dark:hover:text-blue-300 transition-colors duration-300">{t('footer.quickLinks.courses')}</Link></li>
                                <li><Link to="/apply" className="text-gray-300 dark:text-gray-400 hover:text-blue-400 dark:hover:text-blue-300 transition-colors duration-300">{t('footer.quickLinks.apply')}</Link></li>
                                <li><Link to="/contact" className="text-gray-300 dark:text-gray-400 hover:text-blue-400 dark:hover:text-blue-300 transition-colors duration-300">{t('footer.quickLinks.contact')}</Link></li>
                                <li><Link to="/news" className="text-gray-300 dark:text-gray-400 hover:text-blue-400 dark:hover:text-blue-300 transition-colors duration-300">{t('footer.quickLinks.news')}</Link></li>
                            </ul>
                        </div>

                        <div className="footer-section">
                            <h4 className="footer-title text-white dark:text-gray-100 transition-colors duration-300">{t('footer.programs.title')}</h4>
                            <ul className="footer-links">
                                <li><Link to="/courses/web-development" className="text-gray-300 dark:text-gray-400 hover:text-blue-400 dark:hover:text-blue-300 transition-colors duration-300">{t('footer.programs.webDevelopment')}</Link></li>
                                <li><Link to="/courses/data-science" className="text-gray-300 dark:text-gray-400 hover:text-blue-400 dark:hover:text-blue-300 transition-colors duration-300">{t('footer.programs.dataScience')}</Link></li>
                                <li><Link to="/courses/cybersecurity" className="text-gray-300 dark:text-gray-400 hover:text-blue-400 dark:hover:text-blue-300 transition-colors duration-300">{t('footer.programs.cybersecurity')}</Link></li>
                                <li><Link to="/courses/cloud-computing" className="text-gray-300 dark:text-gray-400 hover:text-blue-400 dark:hover:text-blue-300 transition-colors duration-300">{t('footer.programs.cloudComputing')}</Link></li>
                                <li><Link to="/courses/ai-ml" className="text-gray-300 dark:text-gray-400 hover:text-blue-400 dark:hover:text-blue-300 transition-colors duration-300">{t('footer.programs.aiMl')}</Link></li>
                                <li><Link to="/courses/mobile-development" className="text-gray-300 dark:text-gray-400 hover:text-blue-400 dark:hover:text-blue-300 transition-colors duration-300">{t('footer.programs.mobileDevelopment')}</Link></li>
                            </ul>
                        </div>

                        <div className="footer-section">
                            <h4 className="footer-title text-white dark:text-gray-100 transition-colors duration-300">{t('footer.support.title')}</h4>
                            <ul className="footer-links">
                                <li><Link to="/help" className="text-gray-300 dark:text-gray-400 hover:text-blue-400 dark:hover:text-blue-300 transition-colors duration-300">{t('footer.support.helpCenter')}</Link></li>
                                <li><Link to="/faq" className="text-gray-300 dark:text-gray-400 hover:text-blue-400 dark:hover:text-blue-300 transition-colors duration-300">{t('footer.support.faq')}</Link></li>
                                <li><Link to="/student-portal" className="text-gray-300 dark:text-gray-400 hover:text-blue-400 dark:hover:text-blue-300 transition-colors duration-300">{t('footer.support.studentPortal')}</Link></li>
                                <li><Link to="/career-services" className="text-gray-300 dark:text-gray-400 hover:text-blue-400 dark:hover:text-blue-300 transition-colors duration-300">{t('footer.support.careerServices')}</Link></li>
                                <li><Link to="/alumni" className="text-gray-300 dark:text-gray-400 hover:text-blue-400 dark:hover:text-blue-300 transition-colors duration-300">{t('footer.support.alumni')}</Link></li>
                                <li><Link to="/library" className="text-gray-300 dark:text-gray-400 hover:text-blue-400 dark:hover:text-blue-300 transition-colors duration-300">{t('footer.support.library')}</Link></li>
                            </ul>
                        </div>

                        <div className="footer-section footer-contact">
                            <h4 className="footer-title text-white dark:text-gray-100 transition-colors duration-300">{t('footer.contact.title')}</h4>
                            <div className="contact-info">
